def load_macro_cache(fname, label):
    p = FRED / f"{fname}.json"
    if not p.exists(): return None
    d = json.load(open(p))
    obs = pd.DataFrame(d["data"])
    obs["date"] = pd.to_datetime(obs["date"])
    obs["value"] = pd.to_numeric(obs["value"], errors="coerce")
    s = obs.set_index("date")["value"].sort_index()
    s.index = s.index.to_period("M").to_timestamp()
    s.name = label
    return s


def macro_from_inline(key):
    info = MACROS_INLINE[key]
    df = pd.DataFrame(info["data"], columns=["date","value"])
    df["date"] = pd.to_datetime(df["date"]).dt.to_period("M").dt.to_timestamp()
    s = df.set_index("date")["value"].sort_index()
    s.name = info["label"]
    return s


def all_macros():
    out = {}
    for fname, lbl in [("umich","UMich Sentiment"),
                       ("retail_sales","Retail Sales"),
                       ("nfp","NFP"),
                       ("core_cpi","Core CPI"),
                       ("pce_price","PCE Price")]:
        s = load_macro_cache(fname, lbl)
        if s is not None:
            out[lbl] = s
    for k in MACROS_INLINE:
        out[MACROS_INLINE[k]["label"]] = macro_from_inline(k)
    return out


def yoy_corr(ca, macro, lags=range(-2,3)):
    yc = ca.pct_change(12)
    ym = macro.pct_change(12)
    df = pd.concat([yc.rename("ca"), ym.rename("m")], axis=1, join="inner").dropna()
    out = {"n": len(df)}
    if len(df) < 6:
        for k in lags: out[f"r{k:+d}"] = None
        out["best_lag"], out["best_r"] = None, None
        return out
    for k in lags:
        out[f"r{k:+d}"] = round(df["ca"].shift(k).corr(df["m"]), 3)
    best_k = max(lags, key=lambda k: abs(out[f'r{k:+d}']) if out[f'r{k:+d}'] is not None else -1)
    out["best_lag"] = best_k
    out["best_r"] = out[f"r{best_k:+d}"]
    return out


def aggregate(df, value_col, split_col=None):
    df = df.copy()
    df["date"] = pd.to_datetime(df["date"]).dt.to_period("M").dt.to_timestamp()
    if split_col is None:
        return {"SUM": df.set_index("date")[value_col].sort_index()}
    out = {"SUM": df.groupby("date")[value_col].sum().sort_index()}
    for v in df[split_col].unique():
        sub = df[df[split_col] == v]
        out[v] = sub.set_index("date")[value_col].sort_index()
    return out


def analyze(ds_id, csv_path, value_col, split_col):
    df = pd.read_csv(csv_path)
    aggs = aggregate(df, value_col, split_col)
    macros = all_macros()
    rows = []
    for agg_name, ca_s in aggs.items():
        for m_label, m_s in macros.items():
            r = yoy_corr(ca_s, m_s)
            rows.append({"ca":ds_id,"ca_agg":agg_name,"macro":m_label,**r})
    out = pd.DataFrame(rows)
    out.to_csv(OUT/f"{ds_id.lower()}_multi_macro_corr.csv", index=False)
    return out


def direction_summary(df, agg_name):
    sub = df[df["ca_agg"]==agg_name]
    if sub.empty: return None
    ca_leads = sub[sub["best_lag"]>0]
    contemp = sub[sub["best_lag"]==0]
    macro_leads = sub[sub["best_lag"]<0]
    return {"total":len(sub), "ca_leads":len(ca_leads), "contemp":len(contemp),
            "macro_leads":len(macro_leads),
            "|r|_avg_ca":ca_leads["best_r"].abs().mean() if len(ca_leads) else 0,
            "|r|_avg_macro":macro_leads["best_r"].abs().mean() if len(macro_leads) else 0}


def main():
    print("CA0030 ...")
    r30 = analyze("CA0030", OUT/"ca0030_clickstream_us_monthly_5y.csv",
                  "website_users", "platform_name")
    print("CA0056 ...")
    r56 = analyze("CA0056", OUT/"ca0056_card_spend_us_monthly_5y.csv",
                  "credit_card_spend", "transaction_method")
    print("CA0034 ...")
    r34 = analyze("CA0034", OUT/"ca0034_pos_instore_us_monthly_5y.csv",
                  "pos_volume", None)

    print("\n=== Direction summary per (dataset × aggregation) ===")
    for ds_id, df in [("CA0030 Clickstream", r30),
                       ("CA0056 Card Spend", r56),
                       ("CA0034 POS Instore", r34)]:
        print(f"\n{ds_id}")
        for agg in df["ca_agg"].unique():
            s = direction_summary(df, agg)
            print(f"  {agg:10s}: total={s['total']:2d}  "
                  f"CA leads={s['ca_leads']:2d} (avg|r|={s['|r|_avg_ca']:.2f})  "
                  f"contemp={s['contemp']:2d}  "
                  f"Macro leads={s['macro_leads']:2d} (avg|r|={s['|r|_avg_macro']:.2f})")


if __name__ == "__main__":
    main()
